from datetime import datetime

class DataAccess:
    def __init__(self, base_url):
        self.base_url = base_url

    def get_resource(self, resource_type, resource_id, access_token):
        headers = {'Authorization': f"Bearer {access_token}"}
        response = requests.get(f"{self.base_url}/{resource_type}/{resource_id}", headers=headers)

